-- Ensure base organization exists for local multi-tenant auth testing.
VALUES ('0f0f6e4a-9ad9-438a-b064-1f42b7100001', 'Loam Demo Operations')
ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name;

-- Seed profiles + memberships if local auth users are available.
WITH users_limited AS (
  SELECT id, email
  FROM auth.users
  ORDER BY created_at
  LIMIT 3
)
SELECT id, split_part(coalesce(email, 'Demo User'), '@', 1), email
FROM users_limited
ON CONFLICT (id) DO NOTHING;

WITH users_limited AS (
  SELECT id
  FROM auth.users
  ORDER BY created_at
  LIMIT 3
)
SELECT '0f0f6e4a-9ad9-438a-b064-1f42b7100001', id, CASE WHEN row_number() OVER () = 1 THEN 'owner' ELSE 'member' END
FROM users_limited
ON CONFLICT (organization_id, user_id) DO NOTHING;

-- Service types used by plans/visits.
