-- Optional newer tables: app_events + daily_run_state (if present in your local schema).
DO $$
DECLARE
  v_actor uuid;
BEGIN
  SELECT id INTO v_actor FROM auth.users ORDER BY created_at LIMIT 1;

  IF v_actor IS NOT NULL AND to_regclass('public.daily_run_state') IS NOT NULL THEN
    SELECT
      '0f0f6e4a-9ad9-438a-b064-1f42b7100001',
      v_actor,
      current_date,
      'running',
      (SELECT id FROM public.service_visits WHERE status IN ('scheduled', 'rescheduled') ORDER BY scheduled_date LIMIT 1),
      true,
      jsonb_build_object('seed', true, 'source', 'generate-seed.ts')
    ON CONFLICT (organization_id, user_id, run_date)
    DO UPDATE SET phase = EXCLUDED.phase, active_visit_id = EXCLUDED.active_visit_id, confirmed_today = EXCLUDED.confirmed_today, metadata = EXCLUDED.metadata, updated_at = now();
  END IF;

  IF to_regclass('public.app_events') IS NOT NULL THEN
    SELECT
      '0f0f6e4a-9ad9-438a-b064-1f42b7100001',
      v_actor,
      'service_visit',
      sv.id,
      CASE
        WHEN sv.status = 'completed' THEN 'visit_completed'
        WHEN sv.status = 'skipped' THEN 'visit_skipped'
        WHEN sv.status = 'rescheduled' THEN 'visit_rescheduled'
        ELSE 'visit_scheduled'
      END,
      jsonb_build_object('seed', true),
      jsonb_build_object('script', 'generate-seed.ts'),
      'seed'
    FROM public.service_visits sv
    ORDER BY sv.created_at
    LIMIT 200;
  END IF;
END $$;

COMMIT;
